          Database Connection Failed - Running in Offline Mode
        </div>
      )}

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-6">
        {/* Main Store Layout */}
        {(currentView === 'home' || currentView === 'category') && (
          <div className="flex flex-col lg:flex-row gap-8">
            {/* Sidebar */}
            <aside className="w-full lg:w-64 shrink-0 space-y-6">
              {/* Search Mobile - visible only on small screens if needed, but here sticking to sidebar */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-sky-100">
                 <h3 className="font-bold text-slate-800 mb-4 uppercase text-xs tracking-wider">Search Assets</h3>
                 <div className="relative">
                   <input 
                    type="text" 
                    placeholder="Keywords..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-sky-50 border border-sky-200 text-sm rounded-lg pl-3 pr-10 py-2 focus:ring-2 focus:ring-sky-400 outline-none"
                   />
                   <i className="fa-solid fa-search absolute right-3 top-2.5 text-sky-400"></i>
                 </div>
              </div>

              <div className="bg-white p-6 rounded-2xl shadow-sm border border-sky-100">
                <h3 className="font-bold text-slate-800 mb-4 uppercase text-xs tracking-wider">Categories</h3>
                <div className="space-y-2">
                  <button 
                    onClick={() => setSelectedCategory(null)}
                    className={`w-full text-left px-3 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-between group ${!selectedCategory ? 'bg-sky-500 text-white' : 'text-slate-600 hover:bg-sky-50'}`}
                  >
                    <span>All Products</span>
                    <i className={`fa-solid fa-layer-group ${!selectedCategory ? 'text-white' : 'text-sky-300'}`}></i>
